<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Chat Dashboard</title><style>body{margin:0;background:#f8faff;font-family:Inter,Arial,sans-serif;color:#111827}.top{background:#07101e;color:#fff;padding:22px 0}.wrap{width:min(1180px,calc(100% - 40px));margin:auto}.top .wrap{display:flex;justify-content:space-between;gap:18px}.nav{display:flex;gap:18px}a{color:inherit;text-decoration:none}.hero{padding:42px 0}.kicker{color:#2f68ff;font-size:11px;font-weight:900;letter-spacing:.18em;text-transform:uppercase}h1{font-size:42px;letter-spacing:-.055em;margin:10px 0}.grid{display:grid;gap:14px}.card{background:#fff;border:1px solid #edf0f6;border-radius:16px;padding:22px;box-shadow:0 18px 48px rgba(18,30,57,.055);display:grid;grid-template-columns:1fr auto;gap:18px}.meta{color:#667085;font-size:13px;line-height:1.6}.status{font-size:11px;text-transform:uppercase;letter-spacing:.08em;background:#eef4ff;color:#2f68ff;border-radius:999px;padding:7px 10px;font-weight:900}.btn{align-self:start;border-radius:999px;background:#07101e;color:#fff;padding:11px 16px;font-size:12px;font-weight:900}@media(max-width:720px){.card,.top .wrap{grid-template-columns:1fr;display:grid}}</style></head><body><header class="top"><div class="wrap"><strong>David Evans CRM</strong><nav class="nav"><a href="/admin/dashboard.php">Requests</a><a href="/admin/analytics.php">Analytics</a><a href="/admin/account.php">Account</a><a href="/admin/logout.php">Logout</a></nav></div></header><main class="wrap"><section class="hero"><div class="kicker">Chat Dashboard</div><h1>Website conversations</h1><p class="meta">Multiple visitors can open chat conversations from the website bubble. This dashboard lists active and historical threads.</p></section><section class="grid"><?php foreach ($conversations as $row): ?><article class="card"><div><h2><a href="/admin/chat-thread.php?id=<?= (int)$row['id'] ?>"><?= e($row['name'] ?: $row['email'] ?: 'Visitor conversation #' . $row['id']) ?></a></h2><div class="meta">Status: <span class="status"><?= e($row['status']) ?></span><br>Last message: <?= e($row['last_message'] ?: 'No messages') ?><br>Updated: <?= e($row['updated_at']) ?></div></div><a class="btn" href="/admin/chat-thread.php?id=<?= (int)$row['id'] ?>">Open Thread</a></article><?php endforeach; ?><?php if (!$conversations): ?><div class="card">No chat conversations yet.</div><?php endif; ?></section></main></body></html>
